def get_religion_questions(religion: str, n: int = 10) -> list:
    if religion == "christianity":
        pool = CHRISTIANITY_QUESTIONS
    elif religion == "islam":
        pool = ISLAM_QUESTIONS
    elif religion == "hinduism":
        pool = HINDUISM_QUESTIONS
    elif religion == "both":
        # Mix Christianity and Islam
        half = n // 2
        pool = random.sample(CHRISTIANITY_QUESTIONS, min(half, len(CHRISTIANITY_QUESTIONS))) + \
               random.sample(ISLAM_QUESTIONS, min(n - half, len(ISLAM_QUESTIONS)))
        random.shuffle(pool)
        return pool
    else:
        # All religions
        pool = CHRISTIANITY_QUESTIONS + ISLAM_QUESTIONS + HINDUISM_QUESTIONS
    return random.sample(pool, min(n, len(pool)))
